/* ==========================================================================
   CENTRO CARRELLI — STILL DESIGN SYSTEM (2026)
   ========================================================================== */

@import url('https://fonts.googleapis.com/css2?family=Archivo:wght@400;500;600;700;800;900&family=IBM+Plex+Mono:wght@400;500&display=swap');

html {
    scroll-padding-top: 90px;
}

/* --------------------------------------------------------------------------
   Design Tokens
   -------------------------------------------------------------------------- */
:root {
    --color-orange: #F96815;
    --color-orange-hover: #E25A0C;
    --color-orange-glow: rgba(249, 104, 21, 0.15);

    --color-ink: #1A1A1A;
    --color-graphite: #2F2E2C;
    --color-body: #5C5B59;
    --color-caption: #8A8987;
    --color-border: #E6E5E3;
    --color-surface: #FFFFFF;
    --color-band: #F2F1EF;
    --color-page: #FFFFFF;

    --font-display: 'Archivo', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    --font-body: 'Archivo', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    --font-mono: 'IBM Plex Mono', monospace;

    --radius-none: 0px;
    --radius-sm: 2px;
    --radius-md: 4px;

    --shadow-none: none;
    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
    --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.08);
    --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.12);

    --transition-fast: all 150ms ease-out;
    --transition-base: all 200ms ease-out;
}

/* --------------------------------------------------------------------------
   Global Reset & Base
   -------------------------------------------------------------------------- */
*,
*::before,
*::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
    font-size: 16px;
}

/* 3px orange top rule */
body::before {
    content: '';
    display: block;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 3px;
    background-color: var(--color-orange);
    z-index: 1100;
}

body {
    font-family: var(--font-body);
    background-color: var(--color-page);
    color: var(--color-body);
    line-height: 1.6;
    overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-display);
    color: var(--color-ink);
    font-weight: 800;
    line-height: 1.15;
    letter-spacing: -0.5px;
}

a {
    color: inherit;
    text-decoration: none;
    transition: var(--transition-base);
}

/* --------------------------------------------------------------------------
   Focus States (Accessibility)
   -------------------------------------------------------------------------- */
a:focus-visible,
button:focus-visible,
input:focus-visible,
select:focus-visible,
textarea:focus-visible {
    outline: 2px solid var(--color-orange);
    outline-offset: 2px;
}

/* --------------------------------------------------------------------------
   Buttons
   -------------------------------------------------------------------------- */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 12px 28px;
    font-family: var(--font-display);
    font-size: 0.875rem;
    font-weight: 700;
    border-radius: var(--radius-sm);
    cursor: pointer;
    transition: var(--transition-base);
    border: 2px solid transparent;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    min-height: 48px;
}

.btn-primary {
    background-color: var(--color-orange);
    color: #FFFFFF;
    border-color: var(--color-orange);
}

.btn-primary:hover {
    background-color: var(--color-orange-hover);
    border-color: var(--color-orange-hover);
    transform: translateY(-1px);
    box-shadow: var(--shadow-sm);
}

.btn-secondary {
    background-color: transparent;
    color: var(--color-ink);
    border: 1.5px solid var(--color-ink);
}

.btn-secondary:hover {
    background-color: var(--color-ink);
    color: #FFFFFF;
    transform: translateY(-1px);
}

.btn-light {
    background-color: #FFFFFF;
    color: var(--color-ink);
    border-color: #FFFFFF;
}

.btn-light:hover {
    background-color: var(--color-orange);
    color: #FFFFFF;
    border-color: var(--color-orange);
    transform: translateY(-1px);
}

/* --------------------------------------------------------------------------
   Navigation
   -------------------------------------------------------------------------- */
.nav-header {
    position: fixed;
    top: 3px; /* below the orange top rule */
    left: 0;
    width: 100%;
    z-index: 1000;
    background-color: var(--color-surface);
    border-bottom: 1px solid var(--color-border);
    transition: var(--transition-base);
}

.nav-header.scrolled {
    box-shadow: var(--shadow-sm);
    padding: 0;
}

.nav-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 16px 24px;
    display: flex;
    align-items: center;
    justify-content: flex-start;
}

.nav-logo {
    display: flex;
    align-items: center;
    gap: 12px;
    font-family: var(--font-display);
    font-weight: 900;
    font-size: 1.5rem;
    color: var(--color-ink);
}

.nav-logo img {
    height: 45px !important;
    width: auto !important;
    display: block;
}

.nav-logo span {
    color: var(--color-orange);
}

.nav-logo .badge-30 {
    font-size: 0.65rem;
    background-color: var(--color-orange);
    color: #FFFFFF;
    padding: 2px 6px;
    border-radius: var(--radius-md);
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.nav-menu {
    display: flex;
    list-style: none;
    margin-left: auto;
    padding-left: 40px;
    gap: 24px;
    align-items: center;
}

.nav-item a {
    color: var(--color-body);
    font-size: 0.9rem;
    font-weight: 500;
    padding: 8px 0;
    position: relative;
}

.nav-item a:hover {
    color: var(--color-ink);
}

.nav-item a::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 2px;
    background-color: var(--color-orange);
    transition: var(--transition-base);
}

.nav-item a:hover::after {
    width: 100%;
}

.nav-cta {
    margin-left: 28px;
}

/* Mobile hamburger */
.hamburger {
    display: none;
    flex-direction: column;
    justify-content: space-between;
    width: 28px;
    height: 20px;
    background: transparent;
    border: none;
    cursor: pointer;
    padding: 0;
    margin-left: auto;
    z-index: 1010;
}

.hamburger span {
    width: 100%;
    height: 2px;
    background-color: var(--color-ink);
    border-radius: 1px;
    transition: var(--transition-base);
}

/* --------------------------------------------------------------------------
   Hero Section
   -------------------------------------------------------------------------- */
.hero-section {
    position: relative;
    min-height: auto;
    padding-top: 90px;
    background-color: var(--color-ink);
    display: flex;
    align-items: center;
    overflow: hidden;
}

/* Subtle radial accent — no glow, just a faint warm wash */
.hero-section::before {
    content: '';
    position: absolute;
    bottom: -150px;
    right: -150px;
    width: 600px;
    height: 600px;
    background: radial-gradient(circle, rgba(249, 104, 21, 0.08) 0%, transparent 70%);
    z-index: 1;
    pointer-events: none;
}

.hero-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 24px 24px 20px;
    display: grid;
    grid-template-columns: 1.1fr 0.9fr;
    gap: 24px;
    align-items: center;
    position: relative;
    z-index: 2;
}

.hero-content {
    color: #FFFFFF;
}

.hero-subtitle {
    font-family: var(--font-display);
    color: var(--color-orange);
    font-weight: 700;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    margin-bottom: 16px;
    display: inline-block;
    border-left: 3px solid var(--color-orange);
    padding-left: 10px;
}

.hero-title {
    font-size: 3.5rem;
    font-weight: 900;
    color: #FFFFFF;
    line-height: 1.05;
    margin-bottom: 24px;
    letter-spacing: -1px;
}

.hero-title span {
    color: var(--color-orange);
}

.hero-description {
    font-size: 1.1rem;
    color: rgba(255, 255, 255, 0.65);
    margin-bottom: 36px;
    max-width: 540px;
    line-height: 1.7;
}

.hero-actions {
    display: flex;
    gap: 16px;
    flex-wrap: wrap;
}

.hero-image-wrapper {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
}

.hero-image-container {
    position: relative;
    width: 100%;
    max-width: 380px;
    border-radius: var(--radius-none);
    overflow: hidden;
    border: 1px solid rgba(255, 255, 255, 0.08);
}

.hero-image-container img {
    width: 100%;
    height: auto;
    display: block;
    transition: var(--transition-base);
}

.hero-image-container:hover img {
    transform: scale(1.03);
}

.hero-badge {
    position: absolute;
    bottom: -20px;
    left: -20px;
    background-color: var(--color-orange);
    color: #FFFFFF;
    padding: 20px 24px;
    border-radius: var(--radius-none);
    font-family: var(--font-display);
    z-index: 10;
}

.hero-badge .badge-num {
    font-size: 2.2rem;
    font-weight: 900;
    line-height: 1;
}

.hero-badge .badge-txt {
    font-size: 0.75rem;
    text-transform: uppercase;
    font-weight: 700;
    letter-spacing: 1px;
}

/* --------------------------------------------------------------------------
   Info Strip
   -------------------------------------------------------------------------- */
.info-strip {
    background-color: var(--color-band);
    border-bottom: 3px solid var(--color-orange);
    color: var(--color-ink);
    padding: 28px 0;
}

.info-strip-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 24px;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 30px;
}

.info-item {
    display: flex;
    align-items: center;
    gap: 14px;
}

.info-icon {
    font-size: 1.5rem;
    color: var(--color-orange);
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}

.info-text h4 {
    color: var(--color-ink);
    font-size: 0.95rem;
    font-weight: 700;
    margin-bottom: 2px;
}

.info-text p {
    color: var(--color-body);
    font-size: 0.8rem;
}

/* --------------------------------------------------------------------------
   Finder Section (Configuratore)
   -------------------------------------------------------------------------- */
.finder-section {
    padding: 50px 0;
    background-color: var(--color-surface);
}

.section-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 24px;
}

.section-header {
    text-align: center;
    max-width: 700px;
    margin: 0 auto 60px auto;
}

.section-tag {
    color: var(--color-orange);
    font-weight: 800;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    margin-bottom: 12px;
    display: block;
    font-family: var(--font-display);
}

.section-title {
    font-size: 2.5rem;
    font-weight: 900;
    margin-bottom: 16px;
    letter-spacing: -0.5px;
    color: var(--color-ink);
}

.section-subtitle {
    color: var(--color-caption);
    font-size: 1.05rem;
    line-height: 1.6;
}

/* Finder Widget */
.finder-widget {
    background-color: var(--color-surface);
    border-radius: var(--radius-none);
    border: 1px solid var(--color-border);
    display: grid;
    grid-template-columns: 340px 1fr;
    overflow: hidden;
    min-height: 550px;
}

.finder-sidebar {
    background-color: var(--color-graphite);
    color: #FFFFFF;
    padding: 40px 28px;
}

.finder-sidebar h3 {
    color: #FFFFFF;
    font-size: 1.3rem;
    margin-bottom: 8px;
    border-bottom: 2px solid var(--color-orange);
    padding-bottom: 10px;
}

.finder-sidebar p {
    color: rgba(255, 255, 255, 0.55);
    font-size: 0.85rem;
    margin-bottom: 28px;
}

.filter-group {
    margin-bottom: 22px;
}

.filter-label {
    display: block;
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 10px;
    color: rgba(255, 255, 255, 0.75);
}

.filter-options {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

/* Filter buttons / custom radios */
.filter-btn {
    display: block;
    position: relative;
    padding: 11px 14px;
    background-color: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-sm);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 500;
    color: rgba(255, 255, 255, 0.85);
    transition: var(--transition-fast);
    user-select: none;
    min-height: 44px;
}

.filter-btn input {
    position: absolute;
    opacity: 0;
    cursor: pointer;
    height: 0;
    width: 0;
}

.filter-btn:hover {
    background-color: rgba(255, 255, 255, 0.08);
    border-color: rgba(255, 255, 255, 0.2);
}

.filter-btn.active {
    border-color: var(--color-orange);
    background-color: rgba(249, 104, 21, 0.08);
    color: var(--color-orange);
}

/* Finder results */
.finder-results {
    padding: 36px;
    background-color: var(--color-surface);
    display: flex;
    flex-direction: column;
}

.results-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 28px;
    border-bottom: 1px solid var(--color-border);
    padding-bottom: 14px;
}

.results-count {
    font-weight: 600;
    color: var(--color-ink);
    font-size: 0.9rem;
}

.results-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 24px;
    flex-grow: 1;
}

/* --------------------------------------------------------------------------
   Product Cards
   -------------------------------------------------------------------------- */
.product-card {
    background-color: var(--color-surface);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-none);
    overflow: hidden;
    transition: var(--transition-base);
    display: flex;
    flex-direction: column;
}

.product-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-sm);
    border-color: rgba(249, 104, 21, 0.3);
}

.product-img {
    height: 180px;
    background-color: var(--color-band);
    position: relative;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 10px;
}

.product-img img {
    max-height: 90%;
    max-width: 90%;
    object-fit: contain;
    transition: var(--transition-base);
}

.product-card:hover .product-img img {
    transform: scale(1.04);
}

.product-tag {
    position: absolute;
    top: 12px;
    left: 12px;
    background-color: var(--color-ink);
    color: #FFFFFF;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 3px 8px;
    border-radius: var(--radius-sm);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.product-tag.litio {
    background-color: #10B981;
}

.product-tag.bestseller {
    background-color: #3B82F6;
}

.product-tag.termico {
    background-color: #D97706;
}

.product-info {
    padding: 18px;
    display: flex;
    flex-direction: column;
    flex-grow: 1;
}

.product-brand {
    font-size: 0.75rem;
    color: var(--color-orange);
    text-transform: uppercase;
    font-weight: 700;
    letter-spacing: 1px;
    margin-bottom: 4px;
    font-family: var(--font-display);
}

.product-name {
    font-size: 1.15rem;
    font-weight: 700;
    margin-bottom: 8px;
    color: var(--color-ink);
}

.product-specs {
    list-style: none;
    font-size: 0.82rem;
    color: var(--color-caption);
    margin-bottom: 18px;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 6px 12px;
}

.product-specs li {
    display: flex;
    align-items: center;
    gap: 6px;
}

.product-specs li strong {
    color: var(--color-ink);
}

.product-footer {
    margin-top: auto;
    padding-top: 14px;
    border-top: 1px solid var(--color-border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.product-price-label {
    font-size: 0.7rem;
    color: var(--color-caption);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.product-price {
    font-family: var(--font-display);
    font-size: 1.05rem;
    font-weight: 800;
    color: var(--color-ink);
}

.product-btn {
    background-color: var(--color-orange);
    color: #FFFFFF;
    width: 36px;
    height: 36px;
    border-radius: var(--radius-sm);
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    cursor: pointer;
    transition: var(--transition-fast);
}

.product-btn:hover {
    background-color: var(--color-orange-hover);
    transform: translateY(-1px);
}

/* Empty state */
.empty-state {
    grid-column: 1 / -1;
    text-align: center;
    padding: 60px 20px;
    color: var(--color-caption);
}

.empty-state h3 {
    margin-bottom: 10px;
    color: var(--color-body);
}

/* --------------------------------------------------------------------------
   Anniversary Section (30 Years)
   -------------------------------------------------------------------------- */
.anniversary-section {
    background-color: var(--color-ink);
    color: #FFFFFF;
    padding: 120px 0;
    position: relative;
    overflow: hidden;
}

/* Giant watermark '30' — subtle decoration */
.anniversary-section::before {
    content: '30';
    position: absolute;
    top: 50%;
    left: -50px;
    transform: translateY(-50%);
    font-size: 30vw;
    font-weight: 900;
    font-family: var(--font-display);
    color: rgba(249, 104, 21, 0.03);
    line-height: 1;
    pointer-events: none;
    user-select: none;
}

.anniversary-grid {
    display: grid;
    grid-template-columns: 1.2fr 0.8fr;
    gap: 60px;
    align-items: center;
}

.anniversary-content h2 {
    color: #FFFFFF;
    font-size: 2.8rem;
    margin-bottom: 24px;
    letter-spacing: -1px;
}

.anniversary-content h2 span {
    color: var(--color-orange);
}

.anniversary-content p {
    font-size: 1.05rem;
    color: rgba(255, 255, 255, 0.65);
    margin-bottom: 30px;
    line-height: 1.7;
}

.anniversary-timeline {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 16px;
    margin-bottom: 40px;
}

.timeline-card {
    background-color: rgba(255, 255, 255, 0.04);
    padding: 18px;
    border-radius: var(--radius-none);
    border-top: 3px solid var(--color-orange);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-top: 3px solid var(--color-orange);
}

.timeline-year {
    font-family: var(--font-display);
    font-size: 1.3rem;
    font-weight: 900;
    color: var(--color-orange);
    margin-bottom: 6px;
}

.timeline-title {
    font-weight: 700;
    margin-bottom: 4px;
    font-size: 0.9rem;
    color: #FFFFFF;
}

.timeline-desc {
    font-size: 0.78rem;
    color: rgba(255, 255, 255, 0.45);
}

/* Anniversary seal — static, no animation */
.anniversary-badge-lg {
    display: flex;
    justify-content: center;
    align-items: center;
}

.anniversary-seal {
    width: 260px;
    height: 260px;
    border: 2px solid rgba(249, 104, 21, 0.35);
    border-radius: 50%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    text-align: center;
    padding: 20px;
    position: relative;
}

.anniversary-seal-content {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
}

.anniversary-seal .years {
    font-family: var(--font-display);
    font-size: 5rem;
    font-weight: 900;
    line-height: 1;
    color: var(--color-orange);
}

.anniversary-seal .text-1 {
    font-size: 0.95rem;
    text-transform: uppercase;
    font-weight: 800;
    letter-spacing: 3px;
    margin-top: 4px;
    color: #FFFFFF;
}

.anniversary-seal .text-2 {
    font-size: 0.75rem;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 4px;
}

/* --------------------------------------------------------------------------
   Services Section
   -------------------------------------------------------------------------- */
.services-section {
    padding: 100px 0;
    background-color: var(--color-band);
}

.services-grid {
    display: grid;
    grid-template-columns: 0.95fr 1.05fr;
    gap: 50px;
    align-items: center;
}

.services-image-container {
    border-radius: var(--radius-none);
    overflow: hidden;
    border: 1px solid var(--color-border);
}

.services-image-container img {
    width: 100%;
    height: auto;
    display: block;
}

.services-list {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.service-card {
    display: flex;
    gap: 18px;
    padding: 18px;
    border-radius: var(--radius-none);
    transition: var(--transition-base);
    border: 1px solid transparent;
}

.service-card:hover {
    background-color: var(--color-surface);
    border-color: var(--color-border);
}

.service-num {
    font-family: var(--font-display);
    font-size: 1.4rem;
    font-weight: 900;
    color: var(--color-orange);
    line-height: 1;
    border-right: 2px solid var(--color-orange);
    padding-right: 14px;
    height: fit-content;
}

.service-details h3 {
    font-size: 1.1rem;
    font-weight: 700;
    margin-bottom: 6px;
    color: var(--color-ink);
}

.service-details p {
    color: var(--color-body);
    font-size: 0.9rem;
    line-height: 1.6;
}

/* --------------------------------------------------------------------------
   Articles Section
   -------------------------------------------------------------------------- */
.articles-section {
    padding: 100px 0;
    background-color: var(--color-surface);
}

.articles-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 28px;
    margin-bottom: 50px;
}

.article-card {
    background-color: var(--color-surface);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-none);
    overflow: hidden;
    display: flex;
    flex-direction: column;
    transition: var(--transition-base);
}

.article-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-sm);
    border-color: rgba(249, 104, 21, 0.2);
}

.article-image {
    width: 100%;
    height: 180px;
    overflow: hidden;
}

.article-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.4s ease;
}

.article-card:hover .article-image img {
    transform: scale(1.05);
}

.article-header {
    background-color: var(--color-ink);
    color: #FFFFFF;
    padding: 16px 24px;
    position: relative;
    display: flex;
    align-items: flex-end;
}

.article-header::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 24px;
    width: 40px;
    height: 3px;
    background-color: var(--color-orange);
}

.article-date {
    font-size: 0.75rem;
    color: var(--color-orange);
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-family: var(--font-mono);
}

.article-body {
    padding: 24px;
    display: flex;
    flex-direction: column;
    flex-grow: 1;
}

.article-title {
    font-size: 1.15rem;
    font-weight: 700;
    margin-bottom: 12px;
    line-height: 1.3;
    color: var(--color-ink);
}

.article-excerpt {
    font-size: 0.88rem;
    color: var(--color-body);
    margin-bottom: 20px;
    flex-grow: 1;
    line-height: 1.6;
}

.article-link {
    font-family: var(--font-display);
    font-size: 0.82rem;
    font-weight: 700;
    color: var(--color-ink);
    display: inline-flex;
    align-items: center;
    gap: 6px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.article-link:hover {
    color: var(--color-orange);
}

.article-link span {
    transition: var(--transition-fast);
}

.article-card:hover .article-link span {
    transform: translateX(4px);
}

.articles-cta-container {
    text-align: center;
}

/* --------------------------------------------------------------------------
   Contact Section
   -------------------------------------------------------------------------- */
.contact-section {
    padding: 100px 0;
    background-color: var(--color-graphite);
    color: #FFFFFF;
}

.contact-grid {
    display: grid;
    grid-template-columns: 0.9fr 1.1fr;
    gap: 60px;
    align-items: start;
}

.contact-info-panel h2 {
    color: #FFFFFF;
    font-size: 2.4rem;
    margin-bottom: 16px;
    letter-spacing: -0.5px;
}

.contact-info-panel p {
    color: rgba(255, 255, 255, 0.65);
    margin-bottom: 36px;
    line-height: 1.7;
}

.contact-details {
    display: flex;
    flex-direction: column;
    gap: 20px;
    margin-bottom: 36px;
}

.contact-detail-item {
    display: flex;
    gap: 14px;
    align-items: center;
}

.contact-detail-icon {
    width: 44px;
    height: 44px;
    border-radius: var(--radius-sm);
    background-color: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.15rem;
    color: var(--color-orange);
    flex-shrink: 0;
}

.contact-detail-text h4 {
    color: rgba(255, 255, 255, 0.6);
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    margin-bottom: 2px;
    font-weight: 600;
}

.contact-detail-text p {
    margin-bottom: 0;
    font-size: 1rem;
    color: #FFFFFF;
    font-weight: 500;
}

.social-links {
    display: flex;
    gap: 10px;
}

.social-btn {
    width: 44px;
    height: 44px;
    border-radius: var(--radius-sm);
    background-color: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    color: #FFFFFF;
    transition: var(--transition-fast);
}

.social-btn:hover {
    background-color: var(--color-orange);
    border-color: var(--color-orange);
    color: #FFFFFF;
    transform: translateY(-2px);
}

/* Contact form wrapper */
.contact-form-wrapper {
    background-color: rgba(0, 0, 0, 0.2);
    padding: 36px;
    border-radius: var(--radius-none);
    border: 1px solid rgba(255, 255, 255, 0.08);
}

.contact-form-wrapper h3 {
    color: #FFFFFF;
    font-size: 1.5rem;
    margin-bottom: 6px;
}

.contact-form-wrapper p {
    color: rgba(255, 255, 255, 0.45);
    font-size: 0.85rem;
    margin-bottom: 28px;
}

/* --------------------------------------------------------------------------
   Form Controls
   -------------------------------------------------------------------------- */
.form-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 18px;
}

.form-full {
    grid-column: 1 / -1;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.form-group label {
    font-family: var(--font-display);
    font-size: 0.78rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: rgba(255, 255, 255, 0.6);
}

.form-control {
    width: 100%;
    height: 46px;
    background-color: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius-sm);
    color: #FFFFFF;
    padding: 10px 14px;
    font-family: var(--font-body);
    font-size: 0.95rem;
    transition: var(--transition-fast);
}

.form-control::placeholder {
    color: rgba(255, 255, 255, 0.3);
}

.form-control:focus {
    outline: none;
    border-color: var(--color-orange);
    box-shadow: 0 0 0 2px var(--color-orange-glow);
}

textarea.form-control {
    height: 120px;
    resize: vertical;
}

.form-privacy {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    margin-top: 10px;
}

.form-privacy input[type="checkbox"] {
    margin-top: 4px;
    width: 16px;
    height: 16px;
    accent-color: var(--color-orange);
    cursor: pointer;
    flex-shrink: 0;
}

.form-privacy label {
    font-size: 0.78rem;
    color: rgba(255, 255, 255, 0.45);
    cursor: pointer;
    text-transform: none;
    letter-spacing: 0;
    font-weight: 400;
    line-height: 1.5;
}

.form-privacy a {
    color: var(--color-orange);
    text-decoration: underline;
}

/* --------------------------------------------------------------------------
   Footer
   -------------------------------------------------------------------------- */
.footer-bottom {
    background-color: var(--color-ink);
    color: rgba(255, 255, 255, 0.35);
    padding: 28px 0;
    font-size: 0.82rem;
    border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.footer-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 24px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 16px;
}

.footer-links {
    display: flex;
    gap: 20px;
    list-style: none;
}

.footer-links a {
    color: rgba(255, 255, 255, 0.35);
    transition: var(--transition-fast);
}

.footer-links a:hover {
    color: #FFFFFF;
}

/* --------------------------------------------------------------------------
   Responsive — Tablet (≤ 1024px)
   -------------------------------------------------------------------------- */
@media (max-width: 1024px) {
    .hero-title {
        font-size: 2.6rem;
    }

    .finder-widget {
        grid-template-columns: 1fr;
    }

    .finder-sidebar {
        padding: 28px 24px;
    }

    .info-strip-container {
        grid-template-columns: repeat(2, 1fr);
    }

    .anniversary-grid {
        grid-template-columns: 1fr;
        gap: 40px;
    }

    .anniversary-badge-lg {
        order: -1;
    }

    .services-grid {
        grid-template-columns: 1fr;
    }

    .articles-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .contact-grid {
        grid-template-columns: 1fr;
    }
}

/* --------------------------------------------------------------------------
   Responsive — Mobile (≤ 768px)
   -------------------------------------------------------------------------- */
@media (max-width: 768px) {
    .hamburger {
        display: flex;
    }

    .nav-menu {
        position: fixed;
        top: 0;
        right: -100%;
        width: 80%;
        max-width: 300px;
        height: 100vh;
        background-color: var(--color-surface);
        flex-direction: column;
        justify-content: center;
        gap: 24px;
        padding: 40px;
        transition: var(--transition-base);
        box-shadow: -4px 0 16px rgba(0, 0, 0, 0.08);
        border-left: 1px solid var(--color-border);
    }

    .nav-menu.active {
        right: 0;
    }

    .nav-item a {
        color: var(--color-ink);
        font-size: 1rem;
    }

    .nav-cta {
        margin-left: 0;
        width: 100%;
        text-align: center;
    }

    .nav-cta .btn {
        width: 100%;
    }

    .hero-container {
        grid-template-columns: 1fr;
        text-align: center;
        padding-top: 40px;
    }

    .hero-title {
        font-size: 2.2rem;
    }

    .hero-description {
        margin-left: auto;
        margin-right: auto;
    }

    .hero-actions {
        justify-content: center;
    }

    .hero-badge {
        bottom: -10px;
        left: 50%;
        transform: translateX(-50%);
        width: max-content;
    }

    .info-strip-container {
        grid-template-columns: 1fr;
    }

    .section-title {
        font-size: 1.8rem;
    }

    .anniversary-content h2 {
        font-size: 2rem;
    }

    .anniversary-timeline {
        grid-template-columns: 1fr;
    }

    .anniversary-seal {
        width: 200px;
        height: 200px;
    }

    .anniversary-seal .years {
        font-size: 3.5rem;
    }

    .articles-grid {
        grid-template-columns: 1fr;
    }

    .contact-info-panel h2 {
        font-size: 1.8rem;
    }

    .form-grid {
        grid-template-columns: 1fr;
    }

    .footer-container {
        flex-direction: column;
        text-align: center;
    }

    .footer-links {
        justify-content: center;
    }
}

/* --------------------------------------------------------------------------
   Promo Section — Transpallet in Promozione
   -------------------------------------------------------------------------- */
.promo-section {
    background: linear-gradient(135deg, #1A1A1A 0%, #2F2E2C 100%);
    padding: 80px 0;
    position: relative;
    overflow: hidden;
}

.promo-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, var(--color-orange), #FF8C42, var(--color-orange));
}

.promo-section .section-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 24px;
}

.promo-header {
    text-align: center;
    margin-bottom: 50px;
}

.promo-header .promo-eyebrow {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--color-orange);
    color: #fff;
    padding: 6px 18px;
    border-radius: 20px;
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 0.8rem;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 20px;
}

.promo-header h2 {
    color: #FFFFFF;
    font-size: 2.4rem;
    font-weight: 800;
    margin-bottom: 10px;
    line-height: 1.2;
}

.promo-header h2 span {
    color: var(--color-orange);
}

.promo-header .promo-subtitle {
    color: #B0AFA9;
    font-size: 1.1rem;
    font-weight: 500;
}

.promo-header .promo-urgency {
    display: inline-block;
    margin-top: 15px;
    color: #FF8C42;
    font-family: var(--font-mono);
    font-size: 0.85rem;
    font-weight: 500;
    letter-spacing: 1px;
    text-transform: uppercase;
    border: 1px solid rgba(255, 140, 66, 0.3);
    padding: 6px 16px;
    border-radius: var(--radius-sm);
}

/* Promo Sub-sections */
.promo-subsection {
    margin-bottom: 40px;
}

.promo-subsection:last-child {
    margin-bottom: 0;
}

.promo-subsection-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 24px;
    padding-bottom: 12px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.promo-subsection-tag {
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 0.9rem;
    color: #FFFFFF;
    letter-spacing: 0.5px;
}

.promo-subsection-tag .tag-icon {
    margin-right: 6px;
}

.promo-subsection-line {
    flex: 1;
    height: 1px;
    background: rgba(255, 255, 255, 0.1);
}

/* Promo Cards Grid */
.promo-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 24px;
}

.promo-grid.promo-grid--used {
    grid-template-columns: repeat(2, 1fr);
    max-width: 780px;
}

/* Individual Promo Card */
.promo-card {
    background: #FFFFFF;
    border-radius: var(--radius-md);
    overflow: hidden;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    display: flex;
    flex-direction: column;
}

.promo-card:hover {
    transform: translateY(-6px);
    box-shadow: 0 12px 36px rgba(249, 104, 21, 0.2);
}

.promo-card-image {
    position: relative;
    background: #F5F4F2;
    padding: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 200px;
    overflow: hidden;
}

.promo-card-image img {
    max-width: 100%;
    max-height: 180px;
    object-fit: contain;
    transition: transform 0.3s ease;
}

.promo-card:hover .promo-card-image img {
    transform: scale(1.05);
}

.promo-card-badge {
    position: absolute;
    top: 12px;
    left: 12px;
    padding: 4px 12px;
    border-radius: var(--radius-sm);
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 0.7rem;
    letter-spacing: 1px;
    text-transform: uppercase;
}

.promo-card-badge.badge-new {
    background: var(--color-orange);
    color: #FFFFFF;
}

.promo-card-badge.badge-used {
    background: #4A4A4A;
    color: #FFFFFF;
}

.promo-card-body {
    padding: 20px;
    flex: 1;
    display: flex;
    flex-direction: column;
}

.promo-card-model {
    font-family: var(--font-display);
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--color-caption);
    text-transform: uppercase;
    letter-spacing: 1px;
    margin-bottom: 4px;
}

.promo-card-name {
    font-family: var(--font-display);
    font-size: 1.15rem;
    font-weight: 800;
    color: var(--color-ink);
    margin-bottom: 8px;
    line-height: 1.3;
}

.promo-card-specs {
    list-style: none;
    font-size: 0.82rem;
    color: var(--color-body);
    margin-bottom: 16px;
    line-height: 1.7;
}

.promo-card-specs li::before {
    content: '✓';
    color: var(--color-orange);
    font-weight: 700;
    margin-right: 6px;
}

.promo-card-specs li:has(.spec-icon)::before {
    content: none;
}

svg.spec-icon {
    width: 18px;
    height: 18px;
    margin-right: 6px;
    vertical-align: -3px;
    stroke: #444;
    flex-shrink: 0;
}

.promo-card-footer {
    margin-top: auto;
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    padding-top: 16px;
    border-top: 1px solid var(--color-border);
}

.promo-card-price-block {
    display: flex;
    flex-direction: column;
}

.promo-card-price-label {
    font-size: 0.7rem;
    color: var(--color-caption);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 600;
}

.promo-card-price {
    font-family: var(--font-display);
    font-size: 1.6rem;
    font-weight: 900;
    color: var(--color-orange);
    line-height: 1.2;
}

.promo-card-btn {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    background: var(--color-orange);
    color: #FFFFFF;
    padding: 10px 18px;
    border-radius: var(--radius-sm);
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 0.78rem;
    text-decoration: none;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    transition: var(--transition-fast);
    white-space: nowrap;
}

.promo-card-btn:hover {
    background: var(--color-orange-hover);
    transform: translateY(-1px);
}

/* Promo CTA bottom */
.promo-bottom-cta {
    text-align: center;
    margin-top: 40px;
}

.promo-bottom-cta p {
    color: #8A8987;
    font-size: 0.9rem;
    margin-bottom: 12px;
}

/* Responsive */
@media (max-width: 900px) {
    .promo-grid {
        grid-template-columns: repeat(2, 1fr);
    }
    .promo-grid.promo-grid--used {
        grid-template-columns: 1fr;
        max-width: 380px;
    }
    .promo-header h2 {
        font-size: 1.8rem;
    }
}

@media (max-width: 600px) {
    .promo-section {
        padding: 50px 0;
    }
    .promo-grid {
        grid-template-columns: 1fr;
    }
    .promo-header h2 {
        font-size: 1.5rem;
    }
    .promo-card-price {
        font-size: 1.3rem;
    }
    .promo-card-footer {
        flex-direction: column;
        align-items: flex-start;
        gap: 12px;
    }
    .promo-card-btn {
        width: 100%;
        justify-content: center;
    }
}


/* Modals for Product Details */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.75);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s ease, visibility 0.3s ease;
    backdrop-filter: blur(4px);
}

.modal-overlay.active {
    opacity: 1;
    visibility: visible;
}

.modal-wrapper {
    background: #1A1A1A;
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    width: 90%;
    max-width: 800px;
    max-height: 90vh;
    overflow-y: auto;
    position: relative;
    transform: scale(0.9);
    transition: transform 0.3s ease;
    color: #FFFFFF;
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.5);
}

.modal-overlay.active .modal-wrapper {
    transform: scale(1);
}

.modal-close {
    position: absolute;
    top: 20px;
    right: 20px;
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.1);
    color: #FFFFFF;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: all 0.2s ease;
    font-size: 1.2rem;
    z-index: 10;
}

.modal-close:hover {
    background: var(--color-orange, #F96815);
    border-color: var(--color-orange, #F96815);
}

.modal-content {
    padding: 40px;
}

.modal-hero {
    display: grid;
    grid-template-columns: 180px 1fr;
    gap: 30px;
    align-items: center;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    padding-bottom: 30px;
    margin-bottom: 30px;
}

@media (max-width: 600px) {
    .modal-hero {
        grid-template-columns: 1fr;
        text-align: center;
    }
    .modal-hero img {
        margin: 0 auto;
    }
}

.modal-hero img {
    background: #F5F4F2;
    border-radius: 8px;
    padding: 15px;
    max-width: 100%;
    height: auto;
    object-fit: contain;
}

.modal-title {
    font-size: 2.2rem;
    font-weight: 800;
    margin-bottom: 10px;
    color: #FFFFFF;
    font-family: var(--font-display);
}

.modal-subtitle {
    font-size: 0.85rem;
    color: var(--color-orange, #F96815);
    text-transform: uppercase;
    font-weight: 700;
    letter-spacing: 1.5px;
    margin-bottom: 15px;
    display: inline-block;
}

.modal-description {
    color: rgba(255, 255, 255, 0.7);
    line-height: 1.6;
    font-size: 0.95rem;
}

.modal-grid {
    display: grid;
    grid-template-columns: 1.2fr 1fr;
    gap: 35px;
}

@media (max-width: 768px) {
    .modal-grid {
        grid-template-columns: 1fr;
    }
}

.modal-table-title {
    font-size: 1.1rem;
    font-weight: 700;
    margin-bottom: 15px;
    border-bottom: 2px solid var(--color-orange, #F96815);
    padding-bottom: 8px;
    font-family: var(--font-display);
}

.modal-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.88rem;
}

.modal-table tr {
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.modal-table td {
    padding: 10px 8px;
}

.modal-table td:first-child {
    font-weight: 500;
    color: rgba(255, 255, 255, 0.5);
}

.modal-table td:last-child {
    font-weight: 600;
    color: #FFFFFF;
    text-align: right;
}

.modal-features-list {
    list-style: none;
    padding: 0;
}

.modal-features-list li {
    position: relative;
    padding-left: 24px;
    margin-bottom: 12px;
    font-size: 0.9rem;
    line-height: 1.5;
